import React from "react";
import { motion } from "framer-motion";
import logo from "../assets/logo.png"; // adjust path as needed

const Home = () => {
  return (
    <div className="relative flex flex-col items-center justify-center min-h-screen bg-gradient-to-b from-[#0A0A0A] to-[#111111] text-white overflow-hidden">

      {/* Animated Circular Logo */}
      <motion.div
        className="flex items-center justify-center w-28 h-28 md:w-32 md:h-32 lg:w-36 lg:h-36 rounded-full bg-gradient-to-r from-[#ff6600] to-[#ffaa00] shadow-[0_0_25px_rgba(255,165,0,0.3)]"
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{
          opacity: 1,
          scale: [1, 1.05, 1],
          boxShadow: [
            "0 0 25px rgba(255,165,0,0.3)",
            "0 0 35px rgba(255,165,0,0.5)",
            "0 0 25px rgba(255,165,0,0.3)",
          ],
        }}
        transition={{
          duration: 2.5,
          repeat: Infinity,
          ease: "easeInOut",
        }}
      >
        <motion.img
          src={logo}
          alt="Brand Logo"
          className="w-20 h-20 md:w-24 md:h-24 rounded-full object-cover"
          initial={{ scale: 0.7 }}
          animate={{ scale: 1 }}
          transition={{ duration: 1.2, ease: "easeOut" }}
        />
      </motion.div>

      {/* Hero Message */}
      <motion.h1
        className="text-3xl md:text-5xl font-bold text-center tracking-wide mt-8"
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.4, duration: 1 }}
      >
        Welcome to Godemar’s Empire
      </motion.h1>

      <motion.p
        className="text-lg md:text-xl mt-4 text-gray-300 text-center max-w-xl"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.8, duration: 1 }}
      >
        Innovating beyond boundaries — where creativity meets impact.
      </motion.p>
    </div>
  );
};

export default Home;
